__global__ void Fan1(float *m_dev,
                     float *a_dev,
                     float *b_dev,
                     const int size,
                     const int t) {
    int globalId = blockIdx.x * blockDim.x + threadIdx.x;

    if (globalId < size - 1 - t) {
        m_dev[size * (globalId + t + 1) + t] = a_dev[size * (globalId + t + 1) + t] / a_dev[size * t + t];
    }
}

__global__ void Fan2(float *m_dev,
                     float *a_dev,
                     float *b_dev,
                     const int size,
                     const int t) {
    int globalIdx = blockIdx.x * blockDim.x + threadIdx.x;
    int globalIdy = blockIdx.y * blockDim.y + threadIdx.y;

    if (globalIdx < size - 1 - t && globalIdy < size - t) {
        a_dev[size * (globalIdx + 1 + t) + (globalIdy + t)] -= m_dev[size * (globalIdx + 1 + t) + t] * a_dev[size * t + (globalIdy + t)];

        if (globalIdy == 0) {
            b_dev[globalIdx + 1 + t] -= m_dev[size * (globalIdx + 1 + t) + (globalIdy + t)] * b_dev[t];
        }
    }
}

void InitPerRun(int size, float *m) {
    for (int i = 0; i < size * size; i++) {
        m[i] = 0.0f;
    }
}

void BackSub(float *a, float *b, float *finalVec, int size) {
    for (int i = 0; i < size; i++) {
        finalVec[size - i - 1] = b[size - i - 1];
        for (int j = 0; j < i; j++) {
            finalVec[size - i - 1] -= a[size * (size - i - 1) + (size - j - 1)] * finalVec[size - j - 1];
        }
        finalVec[size - i - 1] = finalVec[size - i - 1] / a[size * (size - i - 1) + (size - i - 1)];
    }
}

void InitMat(FILE *fp, int size, float *ary, int nrow, int ncol) {
    for (int i = 0; i < nrow; i++) {
        for (int j = 0; j < ncol; j++) {
            fscanf(fp, "%f", ary + size * i + j);
        }
    }
}

void InitAry(FILE *fp, float *ary, int ary_size) {
    for (int i = 0; i < ary_size; i++) {
        fscanf(fp, "%f", &ary[i]);
    }
}

void PrintMat(float *ary, int size, int nrow, int ncol) {
    for (int i = 0; i < nrow; i++) {
        for (int j = 0; j < ncol; j++) {
            printf("%8.2f ", ary[size * i + j]);
        }
        printf("\n");
    }
    printf("\n");
}

void PrintAry(float *ary, int ary_size) {
    for (int i = 0; i < ary_size; i++) {
        printf("%.2f ", ary[i]);
    }
    printf("\n");
}

void ForwardSub(float *a, float *b, float *m, int size) {
    float *a_dev, *b_dev, *m_dev;
    cudaError_t err;

    err = cudaMalloc((void **)&a_dev, sizeof(float) * size * size);
    if (err != cudaSuccess) {
        fprintf(stderr, "CUDA malloc a_dev failed: %s\n", cudaGetErrorString(err));
        exit(EXIT_FAILURE);
    }
    err = cudaMalloc((void **)&b_dev, sizeof(float) * size);
    if (err != cudaSuccess) {
        fprintf(stderr, "CUDA malloc b_dev failed: %s\n", cudaGetErrorString(err));
        exit(EXIT_FAILURE);
    }
    err = cudaMalloc((void **)&m_dev, sizeof(float) * size * size);
    if (err != cudaSuccess) {
        fprintf(stderr, "CUDA malloc m_dev failed: %s\n", cudaGetErrorString(err));
        exit(EXIT_FAILURE);
    }

    err = cudaMemcpy(a_dev, a, sizeof(float) * size * size, cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        fprintf(stderr, "CUDA memcpy a_dev failed: %s\n", cudaGetErrorString(err));
        exit(EXIT_FAILURE);
    }
    err = cudaMemcpy(b_dev, b, sizeof(float) * size, cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        fprintf(stderr, "CUDA memcpy b_dev failed: %s\n", cudaGetErrorString(err));
        exit(EXIT_FAILURE);
    }
    err = cudaMemcpy(m_dev, m, sizeof(float) * size * size, cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        fprintf(stderr, "CUDA memcpy m_dev failed: %s\n", cudaGetErrorString(err));
        exit(EXIT_FAILURE);
    }

    for (int t = 0; t < size - 1; t++) {
        int fan1_grid = (size - 1 - t + BLOCK_SIZE_0 - 1) / BLOCK_SIZE_0;
        Fan1<<<fan1_grid, BLOCK_SIZE_0>>>(m_dev, a_dev, b_dev, size, t);
        cudaDeviceSynchronize();

        dim3 fan2_grid((size - 1 - t + BLOCK_SIZE_1_X - 1) / BLOCK_SIZE_1_X,
                       (size - t + BLOCK_SIZE_1_Y - 1) / BLOCK_SIZE_1_Y);
        dim3 fan2_block(BLOCK_SIZE_1_X, BLOCK_SIZE_1_Y);
        Fan2<<<fan2_grid, fan2_block>>>(m_dev, a_dev, b_dev, size, t);
        cudaDeviceSynchronize();
    }

    err = cudaMemcpy(a, a_dev, sizeof(float) * size * size, cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) {
        fprintf(stderr, "CUDA memcpy a failed: %s\n", cudaGetErrorString(err));
        exit(EXIT_FAILURE);
    }
    err = cudaMemcpy(b, b_dev, sizeof(float) * size, cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) {
        fprintf(stderr, "CUDA memcpy b failed: %s\n", cudaGetErrorString(err));
        exit(EXIT_FAILURE);
    }
    err = cudaMemcpy(m, m_dev, sizeof(float) * size * size, cudaMemcpyDeviceToHost);
    if (err != cudaSuccess) {
        fprintf(stderr, "CUDA memcpy m failed: %s\n", cudaGetErrorString(err));
        exit(EXIT_FAILURE);
    }

    cudaFree(a_dev);
    cudaFree(b_dev);
    cudaFree(m_dev);
}

int main(int argc, char **argv) {
    int Size;
    float *a = NULL, *b = NULL, *m = NULL, *finalVec = NULL;
    FILE *fp;

    char filename[30];
    printf("Enter the data file name: ");
    scanf("%29s", filename);
    printf("The file name is: %s\n", filename);

    fp = fopen(filename, "r");
    if (!fp) {
        fprintf(stderr, "Failed to open file %s\n", filename);
        return -1;
    }

    fscanf(fp, "%d", &Size);

    a = (float *)malloc(Size * Size * sizeof(float));
    if (!a) {
        fprintf(stderr, "Failed to allocate memory for matrix a\n");
        fclose(fp);
        return -1;
    }
    InitMat(fp, Size, a, Size, Size);
    printf("The input matrix a is:\n");
    PrintMat(a, Size, Size, Size);

    b = (float *)malloc(Size * sizeof(float));
    if (!b) {
        fprintf(stderr, "Failed to allocate memory for array b\n");
        free(a);
        fclose(fp);
        return -1;
    }
    InitAry(fp, b, Size);
    printf("The input array b is:\n");
    PrintAry(b, Size);

    fclose(fp);

    m = (float *)malloc(Size * Size * sizeof(float));
    if (!m) {
        fprintf(stderr, "Failed to allocate memory for matrix m\n");
        free(a);
        free(b);
        return -1;
    }
    InitPerRun(Size, m);

    finalVec = (float *)malloc(Size * sizeof(float));
    if (!finalVec) {
        fprintf(stderr, "Failed to allocate memory for finalVec\n");
        free(a);
        free(b);
        free(m);
        return -1;
    }

    ForwardSub(a, b, m, Size);

    printf("The result of matrix m is: \n");
    PrintMat(m, Size, Size, Size);
    printf("The result of matrix a is: \n");
    PrintMat(a, Size, Size, Size);
    printf("The result of array b is: \n");
    PrintAry(b, Size);

    BackSub(a, b, finalVec, Size);
    printf("The final solution is: \n");
    PrintAry(finalVec, Size);

    free(a);
    free(b);
    free(m);
    free(finalVec);

    return 0;
}
